evaluators.evaluation_logic:
const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('session_bookings') || '[]');
const coaches = JSON.parse(localStorage.getItem('coaches') || '[]');
const slots = JSON.parse(localStorage.getItem('coach_availability_slots') || '[]');

// Baseline/current time from task config
const baseline = new Date('2026-03-03T09:00:00Z');
const windowEnd = new Date(baseline.getTime() + 7 * 24 * 60 * 60 * 1000);

// Helper: is time between 18:00 and 21:00 inclusive (UTC)
function isInEveningWindow(dateStr) {
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  const h = d.getUTCHours();
  const m = d.getUTCMinutes();
  const minutes = h * 60 + m;
  const start = 18 * 60; // 18:00
  const end = 21 * 60;   // 21:00
  return minutes >= start && minutes <= end;
}

// Determine highest-rated qualifying stress-management coach with a usable slot
const stressCoaches = coaches.filter(c => {
  if (!c || !c.is_active) return false;
  if (!Array.isArray(c.specialties) || !c.specialties.includes('stress_management')) return false;
  if (typeof c.price_per_session !== 'number' || c.price_per_session > 150) return false;
  if (!Array.isArray(c.session_lengths_minutes) || c.session_lengths_minutes.indexOf(60) === -1) return false;
  return true;
});

// For each candidate coach, check if they have at least one available 60-min slot in window 6–9 PM
function hasQualifyingSlot(coachId) {
  return slots.some(s => {
    if (!s || s.coachId !== coachId || s.is_booked) return false;
    const sd = new Date(s.start_datetime);
    const ed = new Date(s.end_datetime);
    if (isNaN(sd.getTime()) || isNaN(ed.getTime())) return false;
    const dur = (ed.getTime() - sd.getTime()) / 60000;
    if (dur < 60) return false;
    if (sd < baseline || sd > windowEnd) return false;
    if (!isInEveningWindow(s.start_datetime)) return false;
    return true;
  });
}

const coachesWithSlots = stressCoaches.filter(c => hasQualifyingSlot(c.id));

let bestCoach = null;
if (coachesWithSlots.length > 0) {
  bestCoach = coachesWithSlots.slice().sort((a, b) => {
    const ar = typeof a.average_rating === 'number' ? a.average_rating : 0;
    const br = typeof b.average_rating === 'number' ? b.average_rating : 0;
    if (br !== ar) return br - ar;
    const av = typeof a.review_count === 'number' ? a.review_count : 0;
    const bv = typeof b.review_count === 'number' ? b.review_count : 0;
    return bv - av;
  })[0];
}

// User-created bookings (ignore seed bookings before baseline)
const userBookings = bookings.filter(b => {
  if (!b) return false;
  const created = new Date(b.created_at || b.start_datetime);
  return !isNaN(created.getTime()) && created >= baseline;
});

// Bookings that satisfy all task constraints (content + time window + price)
const qualifyingUserBookings = userBookings.filter(b => {
  if (!b) return false;
  if (b.topic !== 'stress_management') return false;
  if (b.session_length_minutes !== 60) return false;
  const sd = new Date(b.start_datetime);
  if (isNaN(sd.getTime())) return false;
  if (sd < baseline || sd > windowEnd) return false;
  if (!isInEveningWindow(b.start_datetime)) return false;
  if (typeof b.price !== 'number' || b.price > 150) return false;
  const coach = coaches.find(c => c.id === b.coachId);
  if (!coach) return false;
  if (!Array.isArray(coach.specialties) || !coach.specialties.includes('stress_management')) return false;
  return true;
});

// CP1 (0.4): User booked at least one session that meets ALL session constraints
checkpoints.push({
  passed: qualifyingUserBookings.length >= 1,
  weight: 0.4
});

// CP2 (0.4): Among those bookings, at least one is with the highest-rated qualifying coach
let usedBestCoach = false;
if (bestCoach && qualifyingUserBookings.length > 0) {
  usedBestCoach = qualifyingUserBookings.some(b => b.coachId === bestCoach.id);
}
checkpoints.push({
  passed: !!bestCoach && usedBestCoach,
  weight: 0.4
});

// CP3 (0.2): Exactly one qualifying booking (user booked a single such session)
checkpoints.push({
  passed: qualifyingUserBookings.length === 1,
  weight: 0.2
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('coaching_packages') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

const userCart = carts[0] || null;

// Find all qualifying 4-session career_change packages under $400
const qualifyingPkgs = packages.filter(p => {
  if (!p || !p.is_active) return false;
  if (p.topic !== 'career_change') return false;
  if (p.sessions_count !== 4) return false;
  if (typeof p.price !== 'number' || p.price >= 400) return false;
  return true;
});

let cheapest = null;
if (qualifyingPkgs.length > 0) {
  cheapest = qualifyingPkgs.slice().sort((a, b) => (a.price || 0) - (b.price || 0))[0];
}

let addedCheapest = false;
if (userCart && cheapest) {
  const userCartItems = cartItems.filter(ci => ci && ci.cartId === userCart.id);
  addedCheapest = userCartItems.some(ci => ci.packageId === cheapest.id && (ci.quantity || 0) > 0);
}

// Single combined checkpoint: user added the CHEAPEST qualifying package to their cart
checkpoints.push({
  passed: !!cheapest && !!userCart && addedCheapest,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const lists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const items = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const articles = JSON.parse(localStorage.getItem('blog_articles') || '[]');

const baseline = new Date('2026-03-03T09:00:00Z');
const sixMonthsAgo = new Date('2025-09-03T00:00:00Z');

// Find reading list named exactly 'Productivity Sprint'
const list = lists.find(l => l && l.name === 'Productivity Sprint') || null;

let qualifyingCount = 0;
if (list) {
  const listItems = items.filter(it => it && it.readingListId === list.id);
  const qualifyingArticles = listItems.filter(it => {
    const art = articles.find(a => a.id === it.articleId);
    if (!art) return false;
    // topic: includes 'productivity'
    if (!Array.isArray(art.topic_tags) || !art.topic_tags.includes('productivity')) return false;
    // read time >= 4
    if (typeof art.read_time_minutes !== 'number' || art.read_time_minutes < 4) return false;
    // published within last 6 months (>= sixMonthsAgo)
    const pd = new Date(art.publish_date);
    if (isNaN(pd.getTime()) || pd < sixMonthsAgo || pd > baseline) return false;
    return true;
  });
  qualifyingCount = qualifyingArticles.length;
}

// CP1–3: At least 1, 2, 3 qualifying articles in that list (each 1/3 of score)
[1, 2, 3].forEach((n) => {
  checkpoints.push({
    passed: !!list && qualifyingCount >= n,
    weight: 1 / 3
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const challenges = JSON.parse(localStorage.getItem('challenges') || '[]');
const enrollments = JSON.parse(localStorage.getItem('challenge_enrollments') || '[]');

const baseline = new Date('2026-03-03T09:00:00Z');
const startWindowEnd = new Date(baseline.getTime() + 14 * 24 * 60 * 60 * 1000);

// Qualifying challenges: self_discipline, 14 days, active, start within next 14 days
const qualifyingChallenges = challenges.filter(ch => {
  if (!ch || !ch.is_active) return false;
  if (ch.topic !== 'self_discipline') return false;
  if (ch.duration_days !== 14) return false;
  const sd = new Date(ch.start_date);
  if (isNaN(sd.getTime())) return false;
  return sd >= baseline && sd <= startWindowEnd;
});

const qualifyingIds = new Set(qualifyingChallenges.map(ch => ch.id));

// User enrollments created on/after baseline
const userEnrollments = enrollments.filter(e => {
  if (!e) return false;
  const ed = new Date(e.enrolled_at);
  return !isNaN(ed.getTime()) && ed >= baseline;
});

const matchingEnrollments = userEnrollments.filter(e => {
  if (!qualifyingIds.has(e.challengeId)) return false;
  if (!e.reminder_email_enabled) return false;
  if (e.reminder_sms_enabled) return false;
  if (e.reminder_frequency !== 'daily') return false;
  if (e.reminder_time !== '08:00') return false;
  return true;
});

// Single checkpoint: user has at least one enrollment meeting ALL criteria
checkpoints.push({
  passed: matchingEnrollments.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const assessments = JSON.parse(localStorage.getItem('assessments') || '[]');
const instances = JSON.parse(localStorage.getItem('assessment_instances') || '[]');

const baseline = new Date('2026-03-03T09:00:00Z');

const qualifyingInstances = instances.filter(inst => {
  if (!inst) return false;
  const start = new Date(inst.started_at);
  if (isNaN(start.getTime()) || start < baseline) return false; // treat as user-run if started after baseline
  if (!inst.completed_at) return false;
  if (!inst.saved_to_dashboard) return false;
  const assessment = assessments.find(a => a.id === inst.assessmentId);
  if (!assessment) return false;
  if (!assessment.is_active) return false;
  if (assessment.category !== 'life_balance') return false;
  const qc = assessment.question_count;
  if (typeof qc !== 'number') return false;
  if (qc < 10 || qc > 30) return false;
  return true;
});

// Single checkpoint: at least one qualifying completed-and-saved assessment instance
checkpoints.push({
  passed: qualifyingInstances.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const coaches = JSON.parse(localStorage.getItem('coaches') || '[]');
const messages = JSON.parse(localStorage.getItem('coach_contact_messages') || '[]');

const baseline = new Date('2026-03-03T09:00:00Z');

// Qualifying relationship coaches
const qualifyingCoachIds = new Set(
  coaches.filter(c => {
    if (!c || !c.is_active) return false;
    if (!Array.isArray(c.specialties) || !c.specialties.includes('relationships')) return false;
    if (!c.offers_free_consultation) return false;
    if (typeof c.average_rating !== 'number' || c.average_rating < 4.5) return false;
    if (typeof c.review_count !== 'number' || c.review_count < 10) return false;
    return true;
  }).map(c => c.id)
);

function sentenceCount(text) {
  if (!text) return 0;
  const parts = String(text).split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  return parts.length;
}

const qualifyingMessages = messages.filter(m => {
  if (!m) return false;
  const cd = new Date(m.created_at);
  if (isNaN(cd.getTime()) || cd < baseline) return false; // treat as user message if after baseline
  if (!qualifyingCoachIds.has(m.coachId)) return false;
  if (m.preferred_time_of_day !== 'morning') return false;
  const msgText = String(m.message || '').toLowerCase();
  if (!msgText.includes('communication')) return false;
  if (sentenceCount(m.message) < 2) return false;
  return true;
});

// Single checkpoint: at least one contact message meeting ALL criteria
checkpoints.push({
  passed: qualifyingMessages.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('blog_articles') || '[]');
const savedArticles = JSON.parse(localStorage.getItem('saved_articles') || '[]');
const worksheets = JSON.parse(localStorage.getItem('worksheets') || '[]');
const savedWorksheets = JSON.parse(localStorage.getItem('saved_worksheets') || '[]');

// Qualifying blog bookmarks: topic_tags include 'time_management' AND audience_tags include 'working_parents'
const qualifyingSavedArticles = savedArticles.filter(sa => {
  const art = articles.find(a => a.id === sa.articleId);
  if (!art) return false;
  if (!Array.isArray(art.topic_tags) || !art.topic_tags.includes('time_management')) return false;
  if (!Array.isArray(art.audience_tags) || !art.audience_tags.includes('working_parents')) return false;
  return true;
});

// Qualifying worksheets: topic 'time_management', audience 'working_parents', page_count <= 10
const qualifyingSavedWorksheets = savedWorksheets.filter(sw => {
  const w = worksheets.find(wk => wk.id === sw.worksheetId);
  if (!w) return false;
  if (w.topic !== 'time_management') return false;
  if (w.audience !== 'working_parents') return false;
  if (typeof w.page_count !== 'number' || w.page_count > 10) return false;
  return true;
});

// CP1 (0.5): At least two qualifying blog posts bookmarked
checkpoints.push({
  passed: qualifyingSavedArticles.length >= 2,
  weight: 0.5
});

// CP2 (0.5): At least one qualifying worksheet saved
checkpoints.push({
  passed: qualifyingSavedWorksheets.length >= 1,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('custom_plans') || '[]');
const planItems = JSON.parse(localStorage.getItem('custom_plan_items') || '[]');
const sessions = JSON.parse(localStorage.getItem('individual_session_offerings') || '[]');
const workshops = JSON.parse(localStorage.getItem('group_workshops') || '[]');

// Find latest plan named exactly 'March Focus' (in case of multiples)
const marchPlans = plans.filter(p => p && p.name === 'March Focus');
let plan = null;
if (marchPlans.length > 0) {
  plan = marchPlans.slice().sort((a, b) => {
    const ad = new Date(a.created_at || 0).getTime();
    const bd = new Date(b.created_at || 0).getTime();
    return bd - ad;
  })[0];
}

let itemsForPlan = [];
let indivItems = [];
let workshopItems = [];

if (plan) {
  itemsForPlan = planItems.filter(pi => pi && pi.planId === plan.id);
  indivItems = itemsForPlan.filter(pi => pi.item_type === 'individual_session');
  workshopItems = itemsForPlan.filter(pi => pi.item_type === 'group_workshop');
}

// CP1 (0.4): Plan named 'March Focus' has exactly 2 individual-session items and 1 workshop item
checkpoints.push({
  passed: !!plan && indivItems.length === 2 && workshopItems.length === 1,
  weight: 0.4
});

// CP2 (0.4): All item prices meet thresholds and total plan cost ≤ 300
let pricesOk = false;
if (plan && indivItems.length === 2 && workshopItems.length === 1) {
  const indivOk = indivItems.every(pi => typeof pi.price_snapshot === 'number' && pi.price_snapshot <= 120);
  const workshopOk = workshopItems.every(pi => typeof pi.price_snapshot === 'number' && pi.price_snapshot <= 80);
  const totalOk = typeof plan.total_cost === 'number' && plan.total_cost <= 300;
  pricesOk = indivOk && workshopOk && totalOk;
}
checkpoints.push({
  passed: pricesOk,
  weight: 0.4
});

// CP3 (0.2): Individual sessions are distinct AND workshop topic is productivity/focus
let distinctAndTopicOk = false;
if (plan && indivItems.length === 2 && workshopItems.length === 1) {
  const indivIds = indivItems.map(pi => pi.individualSessionId).filter(Boolean);
  const distinct = new Set(indivIds).size === indivIds.length;
  const workshopEntity = workshops.find(w => w.id === workshopItems[0].groupWorkshopId);
  const topicOk = !!workshopEntity && (workshopEntity.topic === 'productivity' || workshopEntity.topic === 'focus');
  distinctAndTopicOk = distinct && topicOk;
}

checkpoints.push({
  passed: distinctAndTopicOk,
  weight: 0.2
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
